custom_css:
#custom-logo-container {
  position: relative;
  filter: drop-shadow(0 0 5px #fde047) drop-shadow(0 0 10px #f97316);
  animation: flicker 1.5s infinite alternate ease-in-out;
}

@keyframes flicker {
  0% {
    transform: scale(1) rotate(-0.5deg);
    filter: drop-shadow(0 0 4px #fde047) drop-shadow(0 0 12px #f97316) brightness(1);
  }
  25% {
    transform: scale(1.02) rotate(0.5deg);
    filter: drop-shadow(0 0 6px #ffcc00) drop-shadow(0 0 15px #ff4500) brightness(1.2);
  }
  50% {
    transform: scale(0.99) rotate(-0.2deg);
    filter: drop-shadow(0 0 5px #fde047) drop-shadow(0 0 10px #f97316) brightness(1.1);
  }
  75% {
    transform: scale(1.01) rotate(0.3deg);
    filter: drop-shadow(0 0 7px #ffcc00) drop-shadow(0 0 18px #ff4500) brightness(1.3);
  }
  100% {
    transform: scale(1) rotate(0deg);
    filter: drop-shadow(0 0 4px #fde047) drop-shadow(0 0 12px #f97316) brightness(1);
  }
}

#fallback-title {
  background: linear-gradient(to bottom, #fff 20%, #fde047 50%, #f97316 90%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}
